131	void VerilogTestbenchOption::set_top_module(const std::string& top_module) {
132	  /* Precheck: avoid naming conflicts */
133	  if (top_module == generate_fpga_top_module_name() ||
134	      top_module == generate_fpga_core_module_name()) {
135	    VTR_LOG_ERROR(
136	      "Conflicted module name '%s' as top-levle module! Please avoid [%s|%s]\n",
137	      top_module.c_str(), generate_fpga_top_module_name().c_str(),
138	      generate_fpga_core_module_name().c_str());
139	    exit(1);
140	  }
141	  top_module_ = top_module;
142	}
143	
144	void VerilogTestbenchOption::set_dut_module(const std::string& dut_module) {
145	  /* Precheck: only accept two legal names */
146	  if (dut_module != generate_fpga_top_module_name() &&
147	      dut_module != generate_fpga_core_module_name()) {
148	    VTR_LOG_ERROR(
149	      "Invalid module name '%s' for Design Under Test (DUT)! Expect [%s|%s]\n",
150	      dut_module.c_str(), generate_fpga_top_module_name().c_str(),
151	      generate_fpga_core_module_name().c_str());
152	    exit(1);
153	  }
154	  dut_module_ = dut_module;
155	}
