165	  /* Chain effect on other options:
166	   * Enable/disable the print_preconfig_top_testbench and print_top_testbench
167	   */
168	  set_print_preconfig_top_testbench(print_preconfig_top_testbench_);
169	  set_print_top_testbench(print_top_testbench_);
