184	    enabled && (!reference_benchmark_file_path_.empty());
185	  /* Enable print formal verification top_netlist if this is enabled */
186	  if (true == print_preconfig_top_testbench_) {
187	    if (false == print_formal_verification_top_netlist_) {
188	      VTR_LOG_WARN(
189	        "Forcely enable to print top-level Verilog netlist in formal "
190	        "verification purpose as print pre-configured top-level Verilog "
191	        "testbench is enabled\n");
192	      print_formal_verification_top_netlist_ = true;
193	    }
194	  }
195	}
