221	  if (default_net_type ==
222	      std::string(
223	        VERILOG_DEFAULT_NET_TYPE_STRING[VERILOG_DEFAULT_NET_TYPE_NONE])) {
224	    default_net_type_ = VERILOG_DEFAULT_NET_TYPE_NONE;
225	  } else if (default_net_type ==
226	             std::string(VERILOG_DEFAULT_NET_TYPE_STRING
227	                           [VERILOG_DEFAULT_NET_TYPE_WIRE])) {
228	    default_net_type_ = VERILOG_DEFAULT_NET_TYPE_WIRE;
229	  } else {
230	    VTR_LOG_WARN(
231	      "Invalid default net type: '%s'! Expect ['%s'|'%s']\n",
232	      default_net_type.c_str(),
233	      VERILOG_DEFAULT_NET_TYPE_STRING[VERILOG_DEFAULT_NET_TYPE_NONE],
234	      VERILOG_DEFAULT_NET_TYPE_STRING[VERILOG_DEFAULT_NET_TYPE_WIRE]);
235	  }
236	}
