1	/********************************************************************
2	 * This file includes functions that are used to generate
3	 * a Verilog module of a pre-configured FPGA fabric
4	 *******************************************************************/
5	#include <fstream>
6	
7	/* Headers from vtrutil library */
8	#include "command_exit_codes.h"
9	#include "vtr_assert.h"
10	#include "vtr_log.h"
11	#include "vtr_time.h"
12	
13	/* Headers from openfpgautil library */
14	#include "bitstream_manager_utils.h"
15	#include "openfpga_atom_netlist_utils.h"
16	#include "openfpga_digest.h"
17	#include "openfpga_naming.h"
18	#include "openfpga_port.h"
19	#include "openfpga_reserved_words.h"
20	#include "verilog_constants.h"
21	#include "verilog_preconfig_top_module.h"
22	#include "verilog_preconfig_top_module_utils.h"
23	#include "verilog_testbench_utils.h"
24	#include "verilog_writer_utils.h"
25	
26	/* begin namespace openfpga */
27	namespace openfpga {
28	
29	/********************************************************************
30	 * Print module declaration and ports for the pre-configured
31	 * FPGA top module
32	 * The module ports do exactly match the input benchmark
33	 *******************************************************************/
34	static void print_verilog_preconfig_top_module_ports(
35	  std::fstream &fp, const std::string &circuit_name,
36	  const AtomContext &atom_ctx, const VprNetlistAnnotation &netlist_annotation,
37	  const BusGroup &bus_group) {
38	  /* Validate the file stream */
39	  valid_file_stream(fp);
40	
41	  /* Module declaration */
42	  fp << "module " << generate_preconfig_top_module_name(circuit_name);
43	  fp << " (" << std::endl;
44	
45	  /* Port type-to-type mapping */
46	  std::map<AtomBlockType, enum e_dump_verilog_port_type> port_type2type_map;
47	  port_type2type_map[AtomBlockType::INPAD] = VERILOG_PORT_INPUT;
48	  port_type2type_map[AtomBlockType::OUTPAD] = VERILOG_PORT_OUTPUT;
49	
50	  /* Ports to be added, this is to avoid any bus port */
51	  std::vector<BasicPort> port_list;
52	  std::vector<AtomBlockType> port_types;
53	  std::vector<bool> port_big_endian;
54	
55	  /* Print all the I/Os of the circuit implementation to be tested*/
56	  for (const AtomBlockId &atom_blk : atom_ctx.netlist().blocks()) {
57	    /* We only care I/O logical blocks !*/
58	    if ((AtomBlockType::INPAD != atom_ctx.netlist().block_type(atom_blk)) &&
59	        (AtomBlockType::OUTPAD != atom_ctx.netlist().block_type(atom_blk))) {
60	      continue;
61	    }
62	
63	    std::string block_name = atom_ctx.netlist().block_name(atom_blk);
64	    /* The block may be renamed as it contains special characters which violate
65	     * Verilog syntax */
66	    if (true == netlist_annotation.is_block_renamed(atom_blk)) {
67	      VTR_LOG(
68	        "Replace pin name '%s' with '%s' as it is renamed to comply verilog "
69	        "syntax\n",
70	        block_name.c_str(), netlist_annotation.block_name(atom_blk).c_str());
71	      block_name = netlist_annotation.block_name(atom_blk);
72	    }
73	    /* For output block, remove the prefix which is added by VPR */
74	    std::vector<std::string> output_port_prefix_to_remove;
75	    output_port_prefix_to_remove.push_back(
76	      std::string(VPR_BENCHMARK_OUT_PORT_PREFIX));
77	    output_port_prefix_to_remove.push_back(
78	      std::string(OPENFPGA_BENCHMARK_OUT_PORT_PREFIX));
79	    if (AtomBlockType::OUTPAD == atom_ctx.netlist().block_type(atom_blk)) {
80	      for (const std::string &prefix_to_remove : output_port_prefix_to_remove) {
81	        if (!prefix_to_remove.empty()) {
82	          if (0 == block_name.find(prefix_to_remove)) {
83	            block_name.erase(0, prefix_to_remove.length());
84	            break;
85	          }
86	        }
87	      }
88	    }
89	
90	    /* If the pin is part of a bus,
91	     * - Check if the bus is already in the list
92	     *   - If not, add it to the port list
93	     *   - If yes, do nothing and move onto the next port
94	     * If the pin does not belong to any bus
95	     * - Add it to the bus port
96	     */
97	    BusGroupId bus_id = bus_group.find_pin_bus(block_name);
98	    if (bus_id) {
99	      if (port_list.end() == std::find(port_list.begin(), port_list.end(),
100	                                       bus_group.bus_port(bus_id))) {
101	        port_list.push_back(bus_group.bus_port(bus_id));
102	        port_types.push_back(atom_ctx.netlist().block_type(atom_blk));
103	        port_big_endian.push_back(bus_group.is_big_endian(bus_id));
104	      }
105	      continue;
106	    }
107	
108	    /* Both input and output ports have only size of 1 */
109	    BasicPort module_port(std::string(block_name), 1);
110	    port_list.push_back(module_port);
111	    port_types.push_back(atom_ctx.netlist().block_type(atom_blk));
112	    port_big_endian.push_back(true);
113	  }
114	
115	  /* After collecting all the ports, now print the port mapping */
116	  size_t port_counter = 0;
117	  for (size_t iport = 0; iport < port_list.size(); ++iport) {
118	    BasicPort module_port = port_list[iport];
119	    AtomBlockType port_type = port_types[iport];
120	    if (0 < port_counter) {
121	      fp << "," << std::endl;
122	    }
123	
124	    fp << generate_verilog_port(port_type2type_map[port_type], module_port,
125	                                true, !port_big_endian[iport]);
126	
127	    /* Update port counter */
128	    port_counter++;
129	  }
130	
131	  fp << ");" << std::endl;
132	
133	  /* Add an empty line as a splitter */
134	  fp << std::endl;
135	}
136	
137	/********************************************************************
138	 * Impose the bitstream on the configuration memories
139	 * This function uses 'assign' syntax to impost the bitstream at mem port
140	 * while uses 'force' syntax to impost the bitstream at mem_inv port
141	 *******************************************************************/
142	static void print_verilog_preconfig_top_module_force_bitstream(
143	  std::fstream &fp, const std::string &top_block_name,
144	  const BitstreamManager &bitstream_manager, const bool &output_datab_bits,
145	  const bool &little_endian) {
146	  /* Validate the file stream */
147	  valid_file_stream(fp);
148	
149	  print_verilog_comment(
150	    fp, std::string(
151	          "----- Begin assign bitstream to configuration memories -----"));
152	
153	  fp << "initial begin" << std::endl;
154	
155	  for (const ConfigBlockId &config_block_id : bitstream_manager.blocks()) {
156	    /* We only cares blocks with configuration bits */
157	    if (0 == bitstream_manager.block_bits(config_block_id).size()) {
158	      continue;
159	    }
160	    /* Build the hierarchical path of the configuration bit in modules */
161	    std::vector<ConfigBlockId> block_hierarchy =
162	      find_bitstream_manager_block_hierarchy(bitstream_manager, config_block_id,
163	                                             top_block_name);
164	    /* Ensure that this is the module we want to drop! */
165	    VTR_ASSERT(top_block_name ==
166	               bitstream_manager.block_name(block_hierarchy[0]));
167	    block_hierarchy.erase(block_hierarchy.begin());
168	    /* Build the full hierarchy path */
169	    std::string bit_hierarchy_path(FORMAL_VERIFICATION_TOP_MODULE_UUT_NAME);
170	    for (const ConfigBlockId &temp_block : block_hierarchy) {
171	      bit_hierarchy_path += std::string(".");
172	      bit_hierarchy_path += bitstream_manager.block_name(temp_block);
173	    }
174	    bit_hierarchy_path += std::string(".");
175	
176	    /* Find the bit index in the parent block */
177	    BasicPort config_data_port(
178	      bit_hierarchy_path + generate_configurable_memory_data_out_name(),
179	      bitstream_manager.block_bits(config_block_id).size());
180	
181	    /* Wire it to the configuration bit: access both data out and data outb
182	     * ports */
183	    std::vector<size_t> config_data_values;
184	    for (const ConfigBitId config_bit :
185	         bitstream_manager.block_bits(config_block_id)) {
186	      config_data_values.push_back(bitstream_manager.bit_value(config_bit));
187	    }
188	    print_verilog_force_wire_constant_values(fp, config_data_port,
189	                                             config_data_values, little_endian);
190	
191	    if (true == output_datab_bits) {
192	      /* Find the bit index in the parent block */
193	      BasicPort config_datab_port(
194	        bit_hierarchy_path +
195	          generate_configurable_memory_inverted_data_out_name(),
196	        bitstream_manager.block_bits(config_block_id).size());
197	
198	      std::vector<size_t> config_datab_values;
199	      for (const ConfigBitId config_bit :
200	           bitstream_manager.block_bits(config_block_id)) {
201	        config_datab_values.push_back(!bitstream_manager.bit_value(config_bit));
202	      }
203	      print_verilog_force_wire_constant_values(
204	        fp, config_datab_port, config_datab_values, little_endian);
205	    }
206	  }
207	
208	  fp << "end" << std::endl;
209	
210	  print_verilog_comment(
211	    fp,
212	    std::string("----- End assign bitstream to configuration memories -----"));
213	}
214	
215	/********************************************************************
216	 * Impose the bitstream on the configuration memories
217	 * This function uses '$deposit' syntax to do so
218	 *******************************************************************/
219	static void print_verilog_preconfig_top_module_deposit_bitstream(
220	  std::fstream &fp, const std::string &top_block_name,
221	  const BitstreamManager &bitstream_manager, const bool &output_datab_bits,
222	  const bool &little_endian) {
223	  /* Validate the file stream */
224	  valid_file_stream(fp);
225	
226	  print_verilog_comment(
227	    fp, std::string(
228	          "----- Begin deposit bitstream to configuration memories -----"));
229	
230	  fp << "initial begin" << std::endl;
231	
232	  for (const ConfigBlockId &config_block_id : bitstream_manager.blocks()) {
233	    /* We only cares blocks with configuration bits */
234	    if (0 == bitstream_manager.block_bits(config_block_id).size()) {
235	      continue;
236	    }
237	    /* Build the hierarchical path of the configuration bit in modules */
238	    std::vector<ConfigBlockId> block_hierarchy =
239	      find_bitstream_manager_block_hierarchy(bitstream_manager, config_block_id,
240	                                             top_block_name);
241	    /* Drop the first block, which is the top module, it should be replaced by
242	     * the instance name here */
243	    /* Ensure that this is the module we want to drop! */
244	    VTR_ASSERT(top_block_name ==
245	               bitstream_manager.block_name(block_hierarchy[0]));
246	    block_hierarchy.erase(block_hierarchy.begin());
247	
248	    /* Build the full hierarchy path */
249	    std::string bit_hierarchy_path(FORMAL_VERIFICATION_TOP_MODULE_UUT_NAME);
250	    for (const ConfigBlockId &temp_block : block_hierarchy) {
251	      bit_hierarchy_path += std::string(".");
252	      bit_hierarchy_path += bitstream_manager.block_name(temp_block);
253	    }
254	    bit_hierarchy_path += std::string(".");
255	
256	    /* Find the bit index in the parent block */
257	    BasicPort config_data_port(
258	      bit_hierarchy_path + generate_configurable_memory_data_out_name(),
259	      bitstream_manager.block_bits(config_block_id).size());
260	
261	    /* Wire it to the configuration bit: access both data out and data outb
262	     * ports */
263	    std::vector<size_t> config_data_values;
264	    for (const ConfigBitId config_bit :
265	         bitstream_manager.block_bits(config_block_id)) {
266	      config_data_values.push_back(bitstream_manager.bit_value(config_bit));
267	    }
268	    print_verilog_deposit_wire_constant_values(
269	      fp, config_data_port, config_data_values, little_endian);
270	
271	    /* Skip datab ports if specified */
272	    if (false == output_datab_bits) {
273	      continue;
274	    }
275	
276	    BasicPort config_datab_port(
277	      bit_hierarchy_path +
278	        generate_configurable_memory_inverted_data_out_name(),
279	      bitstream_manager.block_bits(config_block_id).size());
280	
281	    std::vector<size_t> config_datab_values;
282	    for (const ConfigBitId config_bit :
283	         bitstream_manager.block_bits(config_block_id)) {
284	      config_datab_values.push_back(!bitstream_manager.bit_value(config_bit));
285	    }
286	    print_verilog_deposit_wire_constant_values(
287	      fp, config_datab_port, config_datab_values, little_endian);
288	  }
289	
290	  fp << "end" << std::endl;
291	
292	  print_verilog_comment(
293	    fp,
294	    std::string("----- End deposit bitstream to configuration memories -----"));
295	}
296	
297	/********************************************************************
298	 * Impose the bitstream on the configuration memories
299	 * We branch here for different simulators:
300	 * 1. iVerilog Icarus prefers using 'assign' syntax to force the values
301	 * 2. Mentor Modelsim prefers using '$deposit' syntax to do so
302	 *******************************************************************/
303	static void print_verilog_preconfig_top_module_load_bitstream(
304	  std::fstream &fp, const std::string &top_block_name,
305	  const CircuitLibrary &circuit_lib, const CircuitModelId &mem_model,
306	  const BitstreamManager &bitstream_manager,
307	  const e_embedded_bitstream_hdl_type &embedded_bitstream_hdl_type,
308	  const bool &little_endian) {
309	  /* Skip the datab port if there is only 1 output port in memory model
310	   * Currently, it assumes that the data output port is always defined while
311	   * datab is optional If we see only 1 port, we assume datab is not defined by
312	   * default.
313	   * TODO: this switch could be smarter: it should identify if only data or
314	   * datab ports are defined.
315	   */
316	  bool output_datab_bits = true;
317	  if (1 == circuit_lib.model_ports_by_type(mem_model, CIRCUIT_MODEL_PORT_OUTPUT)
318	             .size()) {
319	    output_datab_bits = false;
320	  }
321	
322	  print_verilog_comment(
323	    fp,
324	    std::string("----- Begin load bitstream to configuration memories -----"));
325	
326	  /* Use assign syntax for Icarus simulator */
327	  if (EMBEDDED_BITSTREAM_HDL_IVERILOG == embedded_bitstream_hdl_type) {
328	    print_verilog_preconfig_top_module_force_bitstream(
329	      fp, top_block_name, bitstream_manager, output_datab_bits, little_endian);
330	    /* Use deposit syntax for other simulators */
331	  } else if (EMBEDDED_BITSTREAM_HDL_MODELSIM == embedded_bitstream_hdl_type) {
332	    print_verilog_preconfig_top_module_deposit_bitstream(
333	      fp, top_block_name, bitstream_manager, output_datab_bits, little_endian);
334	  }
335	
336	  print_verilog_comment(
337	    fp,
338	    std::string("----- End load bitstream to configuration memories -----"));
339	}
340	
341	/********************************************************************
342	 * Top-level function to generate a Verilog module of
343	 * a pre-configured FPGA fabric.
344	 *
345	 *   Pre-configured FPGA fabric
346	 *                        +--------------------------------------------
347	 *                        |
348	 *                        |          FPGA fabric
349	 *                        |          +-------------------------------+
350	 *                        |          |                               |
351	 *                        |  0/1---->|FPGA global ports              |
352	 *                        |          |                               |
353	 *   benchmark_clock----->|--------->|FPGA_clock                     |
354	 *                        |          |                               |
355	 *   benchmark_inputs---->|--------->|FPGA mapped I/Os               |
356	 *                        |          |                               |
357	 *   benchmark_outputs<---|<---------|FPGA mapped I/Os               |
358	 *                        |          |                               |
359	 *                        |  0/1---->|FPGA unmapped I/Os             |
360	 *                        |          |                               |
361	 *   fabric_bitstream---->|--------->|Internal_configuration_ports   |
362	 *                        |          +-------------------------------+
363	 *                        |
364	 *                        +-------------------------------------------
365	 *
366	 * Note: we do NOT put this module in the module manager.
367	 * Because, it is not a standard module, where we force configuration signals
368	 * This module is a wrapper for the FPGA fabric to be compatible in
369	 * the port map of input benchmark.
370	 * It includes wires to force constant values to part of FPGA datapath I/Os
371	 * All these are hard to implement as a module in module manager
372	 *******************************************************************/
373	int print_verilog_preconfig_top_module(
374	  const ModuleManager &module_manager,
375	  const BitstreamManager &bitstream_manager,
376	  const ConfigProtocol &config_protocol, const CircuitLibrary &circuit_lib,
377	  const FabricGlobalPortInfo &global_ports, const AtomContext &atom_ctx,
378	  const PlacementContext &place_ctx, const PinConstraints &pin_constraints,
379	  const BusGroup &bus_group, const IoLocationMap &io_location_map,
380	  const IoNameMap &io_name_map, const ModuleNameMap &module_name_map,
381	  const VprNetlistAnnotation &netlist_annotation,
382	  const std::string &circuit_name, const std::string &verilog_fname,
383	  const VerilogTestbenchOption &options) {
384	  std::string timer_message =
385	    std::string(
386	      "Write pre-configured FPGA top-level Verilog netlist for design '") +
387	    circuit_name + std::string("'");
388	
389	  int status = CMD_EXEC_SUCCESS;
390	
391	  /* Start time count */
392	  vtr::ScopedStartFinishTimer timer(timer_message);
393	
394	  /* Create the file stream */
395	  std::fstream fp;
396	  fp.open(verilog_fname, std::fstream::out | std::fstream::trunc);
397	
398	  /* Validate the file stream */
399	  check_file_stream(verilog_fname.c_str(), fp);
400	
401	  /* Generate a brief description on the Verilog file*/
402	  std::string title =
403	    std::string("Verilog netlist for pre-configured FPGA fabric by design: ") +
404	    circuit_name;
405	  print_verilog_file_header(fp, title, options.time_stamp());
406	
407	  print_verilog_default_net_type_declaration(fp, options.default_net_type());
408	
409	  /* Print module declaration and ports */
410	  print_verilog_preconfig_top_module_ports(fp, circuit_name, atom_ctx,
411	                                           netlist_annotation, bus_group);
412	
413	  /* Spot the dut module */
414	  ModuleId top_module =
415	    module_manager.find_module(module_name_map.name(options.dut_module()));
416	  if (!module_manager.valid_module_id(top_module)) {
417	    VTR_LOG_ERROR(
418	      "Unable to find the DUT module '%s'. Please check if you create "
419	      "dedicated module when building the fabric!\n",
420	      options.dut_module().c_str());
421	    return CMD_EXEC_FATAL_ERROR;
422	  }
423	  /* Note that we always need the core module as it contains the original port
424	   * names before possible renaming at top-level module. If there is no core
425	   * module, it means that the current top module is the core module */
426	  std::string core_module_name = generate_fpga_core_module_name();
427	  if (module_name_map.name_exist(core_module_name)) {
428	    core_module_name = module_name_map.name(core_module_name);
429	  }
430	  ModuleId core_module = module_manager.find_module(core_module_name);
431	  if (!module_manager.valid_module_id(core_module)) {
432	    core_module = top_module;
433	  }
434	
435	  bool little_endian = options.little_endian();
436	  /* Print internal wires */
437	  print_verilog_preconfig_top_module_internal_wires(
438	    fp, module_manager, core_module,
439	    std::string(FORMAL_VERIFICATION_TOP_MODULE_PORT_POSTFIX), little_endian);
440	
441	  /* Instanciate FPGA top-level module */
442	  print_verilog_testbench_fpga_instance(
443	    fp, module_manager, top_module, core_module,
444	    std::string(FORMAL_VERIFICATION_TOP_MODULE_UUT_NAME),
445	    std::string(FORMAL_VERIFICATION_TOP_MODULE_PORT_POSTFIX), io_name_map,
446	    options.explicit_port_mapping(), little_endian);
447	
448	  /* Find clock ports in benchmark */
449	  std::vector<std::string> benchmark_clock_port_names =
450	    find_atom_netlist_clock_port_names(atom_ctx.netlist(), netlist_annotation);
451	
452	  /* Connect FPGA top module global ports to constant or benchmark global
453	   * signals! */
454	  status = print_verilog_preconfig_top_module_connect_global_ports(
455	    fp, module_manager, core_module, pin_constraints, atom_ctx,
456	    netlist_annotation, global_ports, benchmark_clock_port_names,
457	    std::string(FORMAL_VERIFICATION_TOP_MODULE_PORT_POSTFIX), little_endian);
458	  if (CMD_EXEC_FATAL_ERROR == status) {
459	    return status;
460	  }
461	
462	  /* Connect I/Os to benchmark I/Os or constant driver */
463	  print_verilog_testbench_connect_fpga_ios(
464	    fp, module_manager, core_module, atom_ctx, place_ctx, io_location_map,
465	    netlist_annotation, bus_group,
466	    std::string(FORMAL_VERIFICATION_TOP_MODULE_PORT_POSTFIX), std::string(),
467	    std::string(), std::vector<std::string>(),
468	    (size_t)VERILOG_DEFAULT_SIGNAL_INIT_VALUE, little_endian);
469	
470	  /* Assign the SRAM model applied to the FPGA fabric */
471	  CircuitModelId sram_model = config_protocol.memory_model();
472	  VTR_ASSERT(true == circuit_lib.valid_model_id(sram_model));
473	
474	  /* If we do have the core module, and the dut is specified as core module, the
475	   * hierarchy path when adding should be the instance name of the core module
476	   */
477	  std::string inst_name = module_name_map.name(generate_fpga_top_module_name());
478	  if (options.dut_module() == generate_fpga_core_module_name()) {
479	    ModuleId parent_module = module_manager.find_module(
480	      module_name_map.name(generate_fpga_top_module_name()));
481	    inst_name = module_manager.instance_name(parent_module, core_module, 0);
482	  }
483	
484	  /* Assign FPGA internal SRAM/Memory ports to bitstream values, only output
485	   * when needed */
486	  print_verilog_preconfig_top_module_load_bitstream(
487	    fp, inst_name, circuit_lib, sram_model, bitstream_manager,
488	    options.embedded_bitstream_hdl_type(), little_endian);
489	
490	  /* Add signal initialization:
491	   * Bypass writing codes to files due to the autogenerated codes are very
492	   * large.
493	   */
494	  if (true == options.include_signal_init()) {
495	    print_verilog_testbench_signal_initialization(
496	      fp, std::string(FORMAL_VERIFICATION_TOP_MODULE_UUT_NAME), circuit_lib,
497	      module_manager, top_module, false, little_endian);
498	  }
499	
500	  /* Add waveform output command, support both fsdb and vcd */
501	  if (true == options.dump_waveform()) {
502	    print_verilog_testbench_dump_waveform(
503	      fp, circuit_name, generate_preconfig_top_module_name(circuit_name));
504	  }
505	
506	  /* Testbench ends*/
507	  print_verilog_module_end(
508	    fp,
509	    std::string(circuit_name) +
510	      std::string(FORMAL_VERIFICATION_TOP_MODULE_POSTFIX),
511	    options.default_net_type());
512	
513	  /* Close the file stream */
514	  fp.close();
515	
516	  return status;
517	}
518	
519	} /* end namespace openfpga */
