  shell_cmd.set_option_short_name(le_opt, "le");

  /* add an option '--verbose' */
  shell_cmd.add_option("verbose", false, "enable verbose output");

  /* add command to the shell */
  ShellCommandId shell_cmd_id = shell.add_command(
